{
  "mode": "method",
  "tests": [
    {
      "name": "create_submission_valid",
      "input": {
        "title": "Test Submission",
        "content": "This is a test submission.",
        "userId": "user_123",
        "reviewId": "review_456"
      },
      "output": {
        "id": "submission_1",
        "title": "Test Submission",
        "content": "This is a test submission.",
        "userId": "user_123",
        "reviewId": "review_456",
        "status": "created"
      },
      "notes": "Valid submission creation should return the created submission object."
    },
    {
      "name": "get_submission_valid",
      "input": {
        "id": "submission_1"
      },
      "output": {
        "id": "submission_1",
        "title": "Test Submission",
        "content": "This is a test submission.",
        "userId": "user_123",
        "reviewId": "review_456",
        "status": "created"
      },
      "notes": "Fetching a valid submission should return the correct submission details."
    },
    {
      "name": "update_submission_valid",
      "input": {
        "id": "submission_1",
        "title": "Updated Submission"
      },
      "output": {
        "id": "submission_1",
        "title": "Updated Submission",
        "content": "This is a test submission.",
        "userId": "user_123",
        "reviewId": "review_456",
        "status": "updated"
      },
      "notes": "Updating a submission should reflect the changes in the returned object."
    },
    {
      "name": "delete_submission_valid",
      "input": {
        "id": "submission_1"
      },
      "output": {
        "message": "Submission deleted successfully."
      },
      "notes": "Deleting a submission should confirm successful deletion."
    },
    {
      "name": "create_submission_invalid_user",
      "input": {
        "title": "Test Submission",
        "content": "This is a test submission.",
        "userId": "invalid_user",
        "reviewId": "review_456"
      },
      "output": {
        "error": "User not found."
      },
      "notes": "Attempting to create a submission with an invalid user ID should return an error."
    },
    {
      "name": "get_submission_not_found",
      "input": {
        "id": "invalid_submission"
      },
      "output": {
        "error": "Submission not found."
      },
      "notes": "Fetching a submission that does not exist should return a not found error."
    },
    {
      "name": "update_submission_invalid_id",
      "input": {
        "id": "invalid_submission",
        "title": "Updated Submission"
      },
      "output": {
        "error": "Submission not found."
      },
      "notes": "Updating a submission with an invalid ID should return a not found error."
    },
    {
      "name": "delete_submission_not_found",
      "input": {
        "id": "invalid_submission"
      },
      "output": {
        "error": "Submission not found."
      },
      "notes": "Attempting to delete a non-existent submission should return a not found error."
    }
  ],
  "assumptions": "All IDs are in nanoID format and the database is properly seeded with valid data.",
  "notes": "Ensure that the API maintains backward compatibility with existing services."
}
